// Sequential Visual Flow · Chromatic Storytelling · Print-Ready Asset Management`}]}]},{id:"work-spatial",title:"SPATIAL NARRATIVES",category:"Scenography / Concept Art",year:"2024",role:"CONCEPT ARTIST",client:"COMMERCIAL_PROJECT",description:"Omni Austin Downtown // public area concept art",focusLine:"// FOCUS: THE AUSTIN SESSION — TRANSLATING MUSICAL DNA",narrativeImage:"/images/spatial/RAW_INPUT.png",narrativeText:`Austin, Texas carries a sonic identity unlike any American city. The "Live Music Capital of the World" isn't a tagline — it's an architectural reality: stages on every block, neon against limestone, the persistent hum of a Fender through an open door. The challenge: translate this into permanent visual language for the Omni Austin Downtown public areas — works that speak to locals and visitors alike without illustration or cliché.`,content:["Three large-format works commissioned for the hotel's public areas, translating Austin's musical DNA into abstract spatial compositions.","Each piece deconstructs the geometry of string instruments — bridges, frets, soundholes — into structured geometric systems that hold their own as architectural art."],images:["/images/spatial/ATX_2227_GTR_MAIN.webp","/images/spatial/ATX_2227_GTR_01.png","/images/spatial/ATX_2227_GTR_02.avif"],imageIds:["ATX_2227_GTR_MAIN","ATX_2227_GTR_01","ATX_2227_GTR_02"]}],fT=typeof window>"u"?!1:/Mobi|Android|iPhone|iPad|iPod/i.test(navigator.userAgent),co=typeof window>"u"?!1:/^((?!chrome|android).)*safari/i.test(navigator.userAgent),uu=fT||co,pT=({activeSection:n})=>{const[s,l]=L.useState(null);return f.jsx("div",{className:"fixed inset-0 z-0 flex items-center justify-center pointer-events-none",children:f.jsxs("svg",{className:"w-full h-full max-w-[1600px] max-h-[1200px]",viewBox:"0 0 1000 800",preserveAspectRatio:"xMidYMid slice",style:{overflow:"visible"},children:[f.jsxs("defs",{children:[f.jsxs("filter",{id:"rough-paper",x:"-20%",y:"-20%",width:"140%",height:"140%",filterUnits:"us